import{_ as t,o as s,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"79. Post Registration Students","description":"","frontmatter":{"title":"79. Post Registration Students","eba":"Nurses and Midwives 2024-2028","topics":["classifications","education-pd"]},"headers":[],"relativePath":"ebas/nurses-midwives/education-pd/79-post-registration-students.md","filePath":"ebas/nurses-midwives/education-pd/79-post-registration-students.md"}'),o={name:"ebas/nurses-midwives/education-pd/79-post-registration-students.md"};function a(n,e,d,p,g,l){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_79-post-registration-students" tabindex="-1">79. Post Registration Students <a class="header-anchor" href="#_79-post-registration-students" aria-label="Permalink to &quot;79. Post Registration Students&quot;">​</a></h1><p>This clause does not apply to students covered by <a href="/eba/ebas/nurses-midwives/education-pd/79A-victorian-maternal-and-child-health-nurse-student.html">clause 79A</a>.</p><p><strong>79.1</strong> Post-registration student means an Employee who is:</p><p><strong>(a)</strong> a Registered Nurse or Registered Midwife; and</p><p><strong>(b)</strong> undertaking post-registration study.</p><p><strong>79.2</strong> Post-registration study means:</p><p><strong>(a)</strong> study by a Registered Nurse leading to registration as a midwife; or</p><p><strong>(b)</strong> study by a Registered Nurse or Registered Midwife for the purpose of obtaining a post-registration qualification.</p><p><strong>79.3</strong> Substantive Salary means at the Employee&#39;s appropriate rate of pay according to the Employee&#39;s classification and Years of Experience as a Registered Nurse or Registered Midwife as normally in place before proceeding to commence as a post-registration student. Where the employee is not an Employee covered by this Agreement, substantive salary is to be determined as though the Employee was an Employee of the Employer, immediately before commencing post-registration study.</p><p><strong>79.4</strong> A post-registration student (other than one to whom clause 79.5 applies) who is undertaking the post-registration study within an employment model, will be paid for that period, including periods of clinical placement/supervised experience, at their Substantive Salary.</p><p>Postgraduate Midwifery Students – Employment Model</p><p><strong>79.5</strong> A Registered Nurse undertaking post-graduate midwifery study as part of their employment will:</p><p><strong>(a)</strong> be engaged at a minimum of 0.6 EFT;</p><p><strong>(b)</strong> be paid their substantive rate for all clinical placement/supervised experience that occurs within SCN/Pre Natal/Post Natal/birthing suite; and</p><p><strong>(c)</strong> will not be paid for time outside of the roster save as referred to in (b) above.</p><p>&quot;outside of the roster&quot; for the purposes of this clause means any period where the Employee is not rostered or otherwise not required to be on duty.</p><p><strong>79.5A</strong> The arrangement described at clause 79.5 does not prevent a Registered Nurse from choosing to work additional shifts as a Registered Nurse, in which case those additional shifts will be paid as though the Employee was not in that employment arrangement.</p><p><strong>79.6</strong> A post-registration student who is undertaking the post-registration study outside of any employment arrangement with their Employer, whose Employer has the clinical setting to provide their periods of supervised experience, will pay the Employee their Substantive Salary while undertaking supervised experience (excluding clinical placement).</p><p><strong>79.7</strong> Nothing in clauses 79.4 to 79.6 above affects an Employee&#39;s Level, grade, subgrade or increment otherwise applicable for work performed during the period of study that is not a direct requirement of the post-registration study.</p><p><strong>79.8</strong> The period for which a Registered Nurse or Registered Midwife is paid will be counted in the Employee&#39;s Years of Experience as a Registered Nurse/Registered Midwife.</p><p><strong>79.9</strong> Nothing in this clause will affect more beneficial current arrangements in place with an Employee at the commencement of this Agreement.</p><p>Plain language terms: grad year, graduate, post reg student.</p>',22)])])}const h=t(o,[["render",a]]);export{c as __pageData,h as default};
